@prefix csvw: <http://www.w3.org/ns/csvw#> .
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix ns1: <https://cdif.org/0.1/> .
@prefix ns2: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix ns3: <http://spdx.org/rdf/terms#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a ns2:LongStructureDataSet,
                        ns2:PhysicalDataSet,
                        schema1:DataDownload ;
                    ns2:characterSet "UTF-8" ;
                    ns2:isDelimited true ;
                    schema1:contentUrl "https://example.org/data/gom-water-quality-long-2025.csv" ;
                    schema1:encodingFormat "text/csv" ;
                    schema1:name "Long-form water-quality observations (CSV)" ;
                    ns3:checksum [ a ns3:Checksum ;
                            ns3:algorithm "SHA256" ;
                            ns3:checksumValue "8b1a7c3e5d9f0a2b4c6d8e0f1a3b5c7d9e1f2a4b6c8d0e2f4a6b8c0d2e4f6a8b" ] ;
                    csvw:delimiter "," ;
                    csvw:header true ;
                    csvw:headerRowCount 1 ;
                    csvw:quoteChar "\"" ;
                    csvw:skipBlankRows true ;
                    ns1:fileSize 712 ;
                    ns1:fileSizeUofM "KB" ;
                    ns1:hasPhysicalMapping [ ns2:isRequired true ;
                            ns1:format "string" ;
                            ns1:formats_InstanceVariable <https://example.org/var-parameter> ;
                            ns1:index 2 ;
                            ns1:physicalDataType "string" ],
                        [ ns2:isRequired true ;
                            ns2:nullSequence "NA" ;
                            ns1:format "decimal" ;
                            ns1:formats_InstanceVariable <https://example.org/var-value> ;
                            ns1:index 3 ;
                            ns1:physicalDataType "float64" ],
                        [ ns2:isRequired true ;
                            ns1:format "YYYY-MM-DD" ;
                            ns1:formats_InstanceVariable <https://example.org/var-sample-date> ;
                            ns1:index 1 ;
                            ns1:physicalDataType "date" ],
                        [ ns2:isRequired true ;
                            ns1:format "string" ;
                            ns1:formats_InstanceVariable <https://example.org/var-station> ;
                            ns1:index 0 ;
                            ns1:physicalDataType "string" ],
                        [ ns1:format "string" ;
                            ns1:formats_InstanceVariable <https://example.org/var-unit> ;
                            ns1:index 4 ;
                            ns1:physicalDataType "string" ] ] ;
            sh:resultMessage "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Info ] ] .

